from scipy.stats import norm
from scipy.optimize import brentq
import numpy as np

def bs_put(S, K, r, T, sigma):
    d1=(np.log(S/K)+(r+0.5*sigma**2)*T)/(sigma*np.sqrt(T))
    d2=d1-sigma*np.sqrt(T)
    return K*np.exp(-r*T)*norm.cdf(-d2)-S*norm.cdf(-d1)

def implied_vol(S, K, r, T, market_price):
    f=lambda s: bs_put(S,K,r,T,s)-market_price
    return brentq(f, 0.01, 2.0)

S,K,r,T=185,170,0.045,0.5
print(f"BS price: ${bs_put(S,K,r,T,0.25):.2f}")
print(f"Implied vol: {implied_vol(S,K,r,T,5.27)*100:.1f}%")
